        });

        // Sort logs within each group:
        // 1. By Date DESC (Newest dates first)
        // 2. By Time ASC (Morning to Evening within the same day)
        grouped.forEach(logs => logs.sort((a, b) => {
            const dateCompare = b.log_date.localeCompare(a.log_date);
